content.query:
let waf = AzureDiagnostics
| where ResourceType == "APPLICATIONGATEWAYS"
| where 'value::all' in ({AppGateway}) or Resource in ({AppGateway})
| where Category == "ApplicationGatewayFirewallLog";
let blocked = waf | where action_s == "Blocked" | summarize Blocked = count();
let detected = waf | where action_s == "Detected" | summarize Detected = count();
let allowed = waf | where action_s == "Allowed" or action_s == "" | summarize Allowed = count();
blocked | extend placeholder = 1
| join kind=fullouter (detected | extend placeholder = 1) on placeholder
| join kind=fullouter (allowed | extend placeholder = 1) on placeholder
| project Blocked = coalesce(Blocked, 0), Detected = coalesce(Detected, 0), Allowed = coalesce(Allowed, 0)
